export const getListWellnessExercisesUrl = (params?: ListWellnessExercisesParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : value.toString())
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/wellness/exercises?${stringifiedParams}` : `/api/wellness/exercises`
}

